changeSet.sql:
ALTER TABLE tool_definition
    ADD COLUMN IF NOT EXISTS runtime_env_requirements_json TEXT NOT NULL DEFAULT '[]';

ALTER TABLE mcp_server
    ADD COLUMN IF NOT EXISTS runtime_env_requirements_json TEXT NOT NULL DEFAULT '[]';

ALTER TABLE skill_binding
    ADD COLUMN IF NOT EXISTS runtime_env_requirements_json TEXT NOT NULL DEFAULT '[]';

CREATE TABLE IF NOT EXISTS agent_profile_version_env_var (
    id BIGSERIAL PRIMARY KEY,
    profile_version_id BIGINT NOT NULL REFERENCES agent_profile_version(id) ON DELETE CASCADE,
    env_key VARCHAR(128) NOT NULL,
    description VARCHAR(255),
    secret BOOLEAN NOT NULL DEFAULT TRUE,
    value_source VARCHAR(32) NOT NULL DEFAULT 'INLINE',
    value_encrypted TEXT,
    source_ref VARCHAR(255),
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE UNIQUE INDEX IF NOT EXISTS uk_agent_profile_version_env_var_profile_key
    ON agent_profile_version_env_var(profile_version_id, env_key);

CREATE INDEX IF NOT EXISTS idx_agent_profile_version_env_var_profile
    ON agent_profile_version_env_var(profile_version_id);
